    // DP_prev[k] stores the number of valid sequences ending at k for the previous step (i-1).
    // Indices 0 to 5000 correspond to the number k.
    let dp_prev = new Array(K_MAX + 1).fill(0);

    // Base Case: i = 0
    const S0 = digitSum[0];
    if (S0 <= 50) {
        for (const k of V[S0]) {
            dp_prev[k] = 1;
        }
    }

    // Iterate from i = 1 to N-1
