    const MOD = 1000000007;
    const MAX_VAL = 5000;
    const MAX_S = 50;

    // --- Helper Functions ---

    /**
     * Calculates the sum of digits of a number n.
     * @param {number} n
     * @returns {number}
     */
    const sum_digits = (n) => {
        let sum = 0;
        let s = String(n);
        for (let i = 0; i < s.length; i++) {
            sum += parseInt(s[i]);
        }
        return sum;
    };

    // --- Step 1: Precomputation (V[S] = sorted list of numbers <= 5000 with digit sum S) ---

    // V[S] stores the sorted list of numbers x in [0, 5000] such that sum_digits(x) = S
    const V = Array(MAX_S + 1).fill(0).map(() => []);

    for (let x = 0; x <= MAX_VAL; x++) {
        const S = sum_digits(x);
        if (S <= MAX_S) {
            V[S].push(x);
        }
    }

    // --- Step 2: Dynamic Programming ---

    const N = digitSum.length;

    // DP_prev[j]: Number of valid sequences ending at i-1 where arr[i-1] is V[S_{i-1}][j]
    let DP_prev = [];

    // Base Case i = 0
    const S0 = digitSum[0];
    if (S0 > MAX_S || V[S0].length === 0) {
        return 0;
    }
    DP_prev = Array(V[S0].length).fill(1);

    // Iterate i from 1 to N-1
    for (let i = 1; i < N; i++) {
        const S_prev = digitSum[i - 1];
        const S_curr = digitSum[i];

        const V_prev = V[S_prev];
        const V_curr = V[S_curr];

        if (V_curr.length === 0) {
            return 0; // Impossible to satisfy current digit sum
        }

        // Calculate Cumulative Sums for DP_prev
        const C_prev = new Array(V_prev.length);
        let current_sum = 0;
        for (let k = 0; k < V_prev.length; k++) {
            current_sum = (current_sum + DP_prev[k]) % MOD;
            C_prev[k] = current_sum;
        }

        const DP_curr = new Array(V_curr.length).fill(0);

        // Transition
        for (let j = 0; j < V_curr.length; j++) {
            const v_current = V_curr[j];

            // Find k_max: largest index k in V_prev such that V_prev[k] <= v_current

            // Binary search for the insertion point of v_current + 1 (or upper bound)
            // We look for the first element strictly greater than v_current. Its index - 1 is k_max.
            let low = 0;
            let high = V_prev.length;
            let idx_upper = V_prev.length; 

            while (low < high) {
                const mid = Math.floor((low + high) / 2);
                if (V_prev[mid] > v_current) {
                    idx_upper = mid;
                    high = mid;
                } else {
                    low = mid + 1;
                }
            }

            // k_max is the index right before idx_upper
            const k_max = idx_upper - 1;

            if (k_max >= 0) {
                // Sum is C_prev[k_max]
                DP_curr[j] = C_prev[k_max];
            } 
            // else DP_curr[j] remains 0
        }

        DP_prev = DP_curr;
    }

    // --- Step 3: Final Result ---
    let total_count = 0;
    for (const count of DP_prev) {
        total_count = (total_count + count) % MOD;
    }

    return total_count;
}
