    };

    const N = digitSum.length;

    // DP_prev[v] stores the number of valid sequences ending at value v for the previous step (i-1)
    let DP_prev = new Array(DP_SIZE).fill(0);

    // Base Case: i = 0
    const S0 = digitSum[0];
    for (let v = 0; v <= MAX_VALUE; v++) {
        if (calculateDigitSum(v) === S0) {
            DP_prev[v] = 1;
        }
    }

    // Iterative DP: i = 1 to N-1
    for (let i = 1; i < N; i++) {
        const S_curr = digitSum[i];
        const S_prev = digitSum[i - 1];
        let DP_curr = new Array(DP_SIZE).fill(0);

        // 1. Calculate PrefixSum based on DP_prev (constrained by S_prev)
        // PrefixSum[k] stores sum of DP_prev[u] for u <= k where digitSum(u) == S_prev
        let PrefixSum = new Array(DP_SIZE).fill(0);
        let currentSum = 0;

        for (let k = 0; k <= MAX_VALUE; k++) {
            if (calculateDigitSum(k) === S_prev) {
                currentSum = (currentSum + DP_prev[k]) % MOD;
            }
            PrefixSum[k] = currentSum;
        }

        // 2. Calculate DP_curr
        for (let v = 0; v <= MAX_VALUE; v++) {
            if (calculateDigitSum(v) === S_curr) {
                // DP_curr[v] = sum(DP_prev[u]) for u <= v AND digitSum(u) == S_prev
                DP_curr[v] = PrefixSum[v];
            }
            // If digitSum(v) != S_curr, DP_curr[v] remains 0
        }

        // Update for next iteration
        DP_prev = DP_curr;
    }

    // Final Result: Sum up all counts in the last DP array
    let totalCount = 0;
    for (let v = 0; v <= MAX_VALUE; v++) {
        totalCount = (totalCount + DP_prev[v]) % MOD;
    }

    return totalCount;
}
